/* == EXEMPLE ================================================
 * Mini bump allocator avec un buffer de 64 octets
 * Alloc = avancer un curseur. Reset = remettre a zero.
 * =========================================================== */
typedef struct { char buf[64]; size_t off; } MiniArena;

void *mini_alloc(MiniArena *a, size_t s) {
    if (a->off + s > 64) return NULL;
    void *p = &a->buf[a->off];
    a->off += s;
    return p;
}
void example_demo(void) {
    MiniArena a = {{0}, 0};
    int *x = mini_alloc(&a, sizeof(int));
    int *y = mini_alloc(&a, sizeof(int));
    *x = 42; *y = 99;
    printf("x=%d y=%d used=%zu\n", *x, *y, a.off);
    a.off = 0; /* reset */
    printf("apres reset: used=%zu\n", a.off);
}
